import{_ as e,o as t,c as r,a2 as s}from"./chunks/framework.DvFsUg-r.js";const h=JSON.parse('{"title":"공통코드 관리 화면 lego 이식","description":"","frontmatter":{"title":"공통코드 관리 화면 lego 이식","feature_id":"016","status":"done","created":"2026-06-10 20:17 (KST)","date":"2026-06-10T00:00:00.000Z","tags":["frontend","admin","code","common-code","ui-ux","vue","vuetify","feature-006","feature-004"]},"headers":[],"relativePath":"specs/016-code-management-parity/spec.md","filePath":"specs/016-code-management-parity/spec.md","lastUpdated":null}'),a={name:"specs/016-code-management-parity/spec.md"};function n(l,o,i,c,d,g){return t(),r("div",null,[...o[0]||(o[0]=[s('<h1 id="spec-공통코드-관리-화면-lego-이식" tabindex="-1">Spec: 공통코드 관리 화면 lego 이식 <a class="header-anchor" href="#spec-공통코드-관리-화면-lego-이식" aria-label="Permalink to &quot;Spec: 공통코드 관리 화면 lego 이식&quot;">​</a></h1><h2 id="why-문제-목적" tabindex="-1">Why (문제 / 목적) <a class="header-anchor" href="#why-문제-목적" aria-label="Permalink to &quot;Why (문제 / 목적)&quot;">​</a></h2><p>feature 004(플랫폼 백엔드)에는 <strong>공통코드 도메인</strong>이 이미 있다 — <code>/api/v1/codes</code> 로 코드 그룹·코드 항목을 조회/관리하고, 변경은 ADMIN 으로 통제한다. 하지만 feature 006(관리자 콘솔) <strong>프론트엔드에는 공통코드를 다루는 화면이 전혀 없다.</strong> 실무자는 코드 그룹을 만들거나 그룹 안의 코드 항목(값·라벨·정렬·사용여부 등)을 관리할 화면이 없어, 코드 데이터를 손볼 수단이 없다.</p><p>기준 소스 <code>C:/ax/lego</code> 에는 이 경험이 이미 잘 갖춰져 있다.</p><ul><li><strong>코드 그룹 관리</strong> — 그룹 목록(검색·추가·수정·삭제) 화면. 행을 누르면 그 그룹의 코드 항목 화면으로 들어간다(master).</li><li><strong>코드 항목 관리</strong> — 선택한 그룹에 속한 코드 항목 목록(추가·수정·삭제) 화면. 값·라벨·정렬·확장속성·사용여부를 편집한다(detail).</li><li><strong>CodeSelect</strong> — 특정 코드 그룹의 항목을 불러와 드롭다운으로 보여주는 <strong>재사용 컴포넌트</strong>. 다른 폼에서 공통코드를 고를 때 쓴다.</li></ul><p>이 기능은 lego 의 공통코드 관리 <strong>화면·상호작용</strong>을 관리자 콘솔로 <strong>그대로 이식</strong>해, 이미 존재하는 백엔드(<code>/api/v1/codes</code>)를 화면에서 쓸 수 있게 한다. 같은 제품군에서 화면을 오갈 때의 학습 비용·이질감을 없애고, 코드 데이터 운영 공백을 메운다.</p><h2 id="what-범위" tabindex="-1">What (범위) <a class="header-anchor" href="#what-범위" aria-label="Permalink to &quot;What (범위)&quot;">​</a></h2><h3 id="포함" tabindex="-1">포함 <a class="header-anchor" href="#포함" aria-label="Permalink to &quot;포함&quot;">​</a></h3><p>관리자 콘솔에 <strong>공통코드 관리 영역(프론트엔드)</strong> 을 lego 와 동일한 작업 경험으로 새로 추가한다. <strong>기존 백엔드(<code>/api/v1/codes</code>)를 그대로 재사용</strong>한다(백엔드 무변경).</p><ul><li><strong>코드 그룹 관리 화면(master)</strong><ul><li>그룹 목록 테이블: 그룹코드·그룹명·사용여부(활성/비활성 칩)·액션(수정/삭제).</li><li>키워드 <strong>검색</strong>(그룹코드/그룹명), <strong>추가</strong> 버튼.</li><li>추가/수정 <strong>다이얼로그</strong>: 그룹코드(수정 시 잠금)·그룹명·설명·사용여부 스위치, 필수값 검증.</li><li>삭제 <strong>확인 다이얼로그</strong>(대상 그룹코드 표시).</li><li>행 클릭 → 해당 그룹의 <strong>코드 항목 화면으로 이동</strong>.</li></ul></li><li><strong>코드 항목 관리 화면(detail)</strong><ul><li>선택한 그룹의 코드 항목 테이블: 코드값·코드라벨·정렬순서·사용여부·확장속성·액션.</li><li><strong>추가</strong> 버튼, 추가/수정 <strong>다이얼로그</strong>: 코드값(수정 시 잠금)·코드라벨·정렬순서· 확장속성·사용여부 스위치, 필수값 검증.</li><li>삭제 <strong>확인 다이얼로그</strong>(대상 코드값 표시).</li></ul></li><li><strong>CodeSelect 재사용 컴포넌트</strong> — 코드 그룹을 지정하면 그 그룹의 (사용 중인) 코드 항목을 불러와 선택 드롭다운으로 제공한다. 다른 화면/폼에서 공통코드를 고를 때 재사용.</li><li><strong>네비게이션 진입점</strong> — 관리자 콘솔 메뉴에서 공통코드 관리로 진입할 수 있게 한다.</li><li><strong>시각 일관성</strong> — 이미 이식된 lego 테마/컴포넌트(카드·테이블·칩·다이얼로그·라운드)를 그대로 따른다.</li></ul><h3 id="제외-non-goals" tabindex="-1">제외 (Non-goals) <a class="header-anchor" href="#제외-non-goals" aria-label="Permalink to &quot;제외 (Non-goals)&quot;">​</a></h3><ul><li><strong>백엔드 변경 없음.</strong> <code>/api/v1/codes</code>(그룹·항목 CRUD, ADMIN 통제)를 <strong>현행 계약 그대로</strong> 사용한다. 필드명·모델을 lego(<code>codeName</code>·<code>attr1/2/3</code>)에 맞춰 바꾸지 않는다 — 화면은 현행 백엔드 필드(<code>codeLabel</code>·<code>extra1</code>·<code>extra2</code>)에 바인딩한다.</li><li>공통코드 외 관리 화면(사용자·역할·부서·메뉴·대시보드)은 대상 아님.</li><li>코드값/그룹 단위의 일괄 가져오기/내보내기(CSV 등)·이력·버전 관리.</li><li>i18n 다국어 문구(한국어 1차 유지).</li><li>인증·접근통제 정책 자체의 변경(조회는 인증, 변경은 ADMIN — 현행 유지).</li></ul><h2 id="clarifications" tabindex="-1">Clarifications <a class="header-anchor" href="#clarifications" aria-label="Permalink to &quot;Clarifications&quot;">​</a></h2><h3 id="session-2026-06-10" tabindex="-1">Session 2026-06-10 <a class="header-anchor" href="#session-2026-06-10" aria-label="Permalink to &quot;Session 2026-06-10&quot;">​</a></h3><ul><li>Q: 현행 백엔드(<code>/api/v1/codes</code>)와 lego 의 필드가 다른데, 코드관리를 어느 깊이까지 lego 와 맞출까? → A: <strong>프론트만 이식 — 기존 백엔드 재사용.</strong> lego 의 화면·상호작용을 가져오되 현행 백엔드 계약(<code>codeLabel</code>·<code>extra1</code>·<code>extra2</code>)에 바인딩한다. 백엔드 무변경.</li><li>Q: lego 의 재사용 컴포넌트 <code>CodeSelect</code> 도 함께 가져올까? → A: <strong>포함.</strong> 관리 2화면 + CodeSelect 재사용 컴포넌트까지 이식한다.</li><li>Q: 기존 백엔드의 그룹 삭제는 코드 항목까지 함께 삭제(cascade)하는데, 그룹 삭제 확인을 어떻게 할까? → A: <strong>항목 동반 삭제 경고.</strong> 삭제 확인 다이얼로그에 &quot;이 그룹의 코드 항목도 함께 삭제됨&quot;을 명시해, 백엔드 cascade 동작과 일치하고 사용자가 데이터 손실을 인지하게 한다(프론트만 변경).</li></ul><h2 id="user-scenarios" tabindex="-1">User Scenarios <a class="header-anchor" href="#user-scenarios" aria-label="Permalink to &quot;User Scenarios&quot;">​</a></h2><ol><li><strong>그룹 관리</strong>: 관리자가 공통코드 관리에 들어가 코드 그룹 목록을 본다. &quot;추가&quot;로 새 그룹(그룹코드·그룹명·설명·사용여부)을 만들고, 기존 그룹을 수정·삭제한다. 키워드로 그룹을 검색한다.</li><li><strong>항목 관리</strong>: 관리자가 그룹 행을 눌러 그 그룹의 코드 항목 화면으로 들어간다. &quot;추가&quot;로 코드 항목(코드값·코드라벨·정렬순서·확장속성·사용여부)을 더하고, 기존 항목을 수정· 삭제한다.</li><li><strong>검증/통제</strong>: 필수값(그룹코드·그룹명, 코드값·코드라벨)이 비면 저장이 막힌다. 코드값· 그룹코드는 수정 화면에서 잠겨 키 변경을 방지한다. 변경 작업은 ADMIN 만 수행한다.</li><li><strong>사용여부 반영</strong>: 비활성(useYn=N) 그룹·항목은 목록에서 시각적으로 구분(비활성 칩)되고, CodeSelect 드롭다운에는 사용 중인 항목만 노출된다.</li><li><strong>재사용 선택</strong>: 다른 폼에서 CodeSelect 에 코드 그룹을 지정하면 그 그룹의 코드 항목이 드롭다운으로 떠, 사용자가 공통코드 값을 고를 수 있다.</li></ol><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="기능-functional" tabindex="-1">기능 (Functional) <a class="header-anchor" href="#기능-functional" aria-label="Permalink to &quot;기능 (Functional)&quot;">​</a></h3><ul><li><strong>FR-1 (그룹 목록·검색)</strong>: 코드 그룹 관리 화면은 그룹 목록을 표로 보여주고, 키워드로 그룹을 검색할 수 있다. 각 그룹의 사용여부가 활성/비활성으로 구분 표시된다.</li><li><strong>FR-2 (그룹 CRUD)</strong>: 관리자는 코드 그룹을 추가·수정·삭제할 수 있다. 추가/수정은 다이얼로그 폼(그룹코드·그룹명·설명·사용여부)으로 하며, 수정 시 그룹코드는 잠긴다. 삭제는 확인 후 수행하되, <strong>삭제 확인 다이얼로그는 그 그룹의 코드 항목도 함께 삭제됨을 경고</strong>한다(백엔드 cascade 동작과 일치).</li><li><strong>FR-3 (master→detail 이동)</strong>: 그룹 목록에서 그룹을 선택하면 해당 그룹의 코드 항목 관리 화면으로 이동한다.</li><li><strong>FR-4 (항목 목록)</strong>: 코드 항목 관리 화면은 선택한 그룹의 코드 항목을 코드값·코드라벨· 정렬순서·사용여부·확장속성과 함께 표로 보여준다.</li><li><strong>FR-5 (항목 CRUD)</strong>: 관리자는 코드 항목을 추가·수정·삭제할 수 있다. 추가/수정은 다이얼로그 폼(코드값·코드라벨·정렬순서·확장속성·사용여부)으로 하며, 수정 시 코드값은 잠긴다. 삭제는 확인 후 수행한다.</li><li><strong>FR-6 (입력 검증)</strong>: 그룹코드·그룹명·코드값·코드라벨 등 필수값이 비면 저장이 막히고 안내가 표시된다.</li><li><strong>FR-7 (CodeSelect 재사용)</strong>: 코드 그룹을 지정받아 그 그룹의 코드 항목을 선택 드롭다운 으로 제공하는 재사용 컴포넌트를 제공한다. 사용 중인 항목만 노출한다.</li><li><strong>FR-8 (권한 통제 일치)</strong>: 조회는 인증 사용자, 생성·수정·삭제는 ADMIN 만 가능하다 — 화면 동작이 백엔드 권한 통제와 일치한다.</li><li><strong>FR-9 (네비 진입점)</strong>: 관리자 콘솔 네비게이션에서 공통코드 관리로 진입할 수 있다.</li></ul><h3 id="비기능-non-functional" tabindex="-1">비기능 (Non-functional) <a class="header-anchor" href="#비기능-non-functional" aria-label="Permalink to &quot;비기능 (Non-functional)&quot;">​</a></h3><ul><li><strong>FR-10 (시각 일관성)</strong>: 색·간격·컴포넌트·상호작용이 lego 및 이미 정합된 다른 관리 화면과 일관된다.</li><li><strong>FR-11 (상태표시)</strong>: 로딩/빈/오류 상태가 명확하고, 목록·다이얼로그가 일반 규모 데이터에서 체감 지연 없이 동작한다.</li><li><strong>FR-12 (회귀 안전·무변경 백엔드)</strong>: 화면은 현행 <code>/api/v1/codes</code> 계약을 그대로 사용하며, 백엔드와 다른 기능에 회귀를 일으키지 않는다.</li></ul><h2 id="key-entities" tabindex="-1">Key Entities <a class="header-anchor" href="#key-entities" aria-label="Permalink to &quot;Key Entities&quot;">​</a></h2><ul><li><strong>코드 그룹(Code Group)</strong>: 그룹코드(키), 그룹명, 설명, 사용여부.</li><li><strong>코드 항목(Code Detail)</strong>: 그룹코드(상위), 코드값(키), 코드라벨, 정렬순서, 확장속성 (extra1·extra2), 사용여부.</li></ul><h2 id="contracts-api-그래프-인터페이스" tabindex="-1">Contracts (API / 그래프 인터페이스) <a class="header-anchor" href="#contracts-api-그래프-인터페이스" aria-label="Permalink to &quot;Contracts (API / 그래프 인터페이스)&quot;">​</a></h2><p><strong>기존 백엔드를 무변경으로 사용한다</strong>(신규/수정 API 없음). 화면이 바인딩하는 현행 계약:</p><ul><li>그룹: <code>GET /api/v1/codes/groups?keyword=</code>, <code>GET /api/v1/codes/groups/{groupCode}</code>, <code>POST/PUT/DELETE /api/v1/codes/groups/{groupCode}</code> — 필드: <code>groupCode·groupName· description·useYn</code>.</li><li>항목: <code>GET /api/v1/codes/groups/{groupCode}/details</code>, <code>POST /api/v1/codes/groups/{groupCode}/details</code>, <code>PUT/DELETE /api/v1/codes/groups/{groupCode}/details/{codeValue}</code> — 필드: <code>codeValue·codeLabel·sortOrder·extra1·extra2·useYn</code>.</li><li>변경 엔드포인트는 ADMIN 통제(현행). 화면은 이 권한 경계를 그대로 따른다.</li></ul><blockquote><p>lego 프론트는 <code>codeName</code>·<code>attr1/2/3</code> 를 쓰지만, 본 이식은 현행 백엔드 필드 (<code>codeLabel</code>·<code>extra1</code>·<code>extra2</code>, 확장속성 2개)에 맞춰 바인딩한다. 정확한 라우트· 컴포넌트 배치·CodeSelect 인터페이스는 plan 단계에서 확정한다.</p></blockquote><h2 id="assumptions-정보-기반-결정" tabindex="-1">Assumptions (정보 기반 결정) <a class="header-anchor" href="#assumptions-정보-기반-결정" aria-label="Permalink to &quot;Assumptions (정보 기반 결정)&quot;">​</a></h2><ul><li><strong>프론트만 이식(확정)</strong>: 백엔드(<code>/api/v1/codes</code>)는 손대지 않고 화면만 추가한다. lego 프론트의 <code>codeName</code>/<code>attr1~3</code> 는 현행 백엔드의 <code>codeLabel</code>/<code>extra1·extra2</code>(2개)에 매핑한다 — 화면 라벨·필드 수는 현행 백엔드를 기준으로 한다.</li><li><strong>CodeSelect 포함(확정)</strong>: 관리 2화면과 함께 재사용 드롭다운 컴포넌트도 이식한다.</li><li><strong>권한 경계 현행 유지</strong>: 조회=인증, 변경=ADMIN. 화면은 이 통제와 일치하게 동작.</li><li><strong>사용여부 의미</strong>: <code>useYn</code>(&#39;Y&#39;/&#39;N&#39;)을 활성/비활성으로 표시하고, CodeSelect 는 사용 중인 항목만 노출한다.</li><li><strong>언어</strong>: 한국어 1차.</li></ul><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li><strong>SC-1</strong>: 관리자가 공통코드 관리에서 코드 그룹을 <strong>검색·추가·수정·삭제</strong>하는 전 과정을 화면만으로 끝낼 수 있고, 필수값 누락은 저장 전에 막히며, 그룹 삭제 시 <strong>코드 항목도 함께 삭제됨이 경고</strong>된다.</li><li><strong>SC-2</strong>: 그룹을 선택하면 그 그룹의 <strong>코드 항목 화면으로 이동</strong>하고, 항목을 추가·수정· 삭제할 수 있다(코드값·코드라벨·정렬·확장속성·사용여부 편집).</li><li><strong>SC-3</strong>: 비활성(useYn=N) 그룹·항목이 목록에서 <strong>시각적으로 구분</strong>되고, CodeSelect 드롭다운에는 <strong>사용 중 항목만</strong> 노출된다.</li><li><strong>SC-4</strong>: 변경 작업이 <strong>ADMIN 에서만</strong> 가능하고, 비권한 사용자에게는 변경 수단이 노출/허용되지 않는다(백엔드 통제와 일치).</li><li><strong>SC-5</strong>: CodeSelect 에 코드 그룹을 지정하면 그 그룹의 코드 항목이 드롭다운으로 떠, 다른 폼에서 공통코드 값을 고를 수 있다.</li><li><strong>SC-6</strong>: 공통코드 관리 화면의 색·간격·상호작용이 lego 및 다른 관리 화면과 <strong>시각적으로 구분되지 않는다</strong>.</li><li><strong>SC-7</strong>: 화면 추가가 <strong>기존 백엔드·다른 기능의 회귀를 일으키지 않는다</strong>(백엔드 무변경).</li></ul><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><p>남은 차단 결정 없음 — <code>/speckit-plan</code> 진행 가능. (정합 깊이 = 프론트만 이식 확정, CodeSelect 포함 확정. 라우트/컴포넌트 배치·필드 매핑 세부는 plan 에서.)</p>',34)])])}const p=e(a,[["render",n]]);export{h as __pageData,p as default};
